    if self.totalEmbeddingDiaries != 0 {
      try visitor.visitSingularInt32Field(value: self.totalEmbeddingDiaries, fieldNumber: 12)
    }
    try unknownFields.traverse(visitor: &visitor)
  }

  static func ==(lhs: User_MetricsSummary, rhs: User_MetricsSummary) -> Bool {
    if lhs.totalMonthlySummaries != rhs.totalMonthlySummaries {return false}
    if lhs.pendingMonthlySummaries != rhs.pendingMonthlySummaries {return false}
    if lhs.autoSummaryMonthlyEnabled != rhs.autoSummaryMonthlyEnabled {return false}
    if lhs.autoLatestTrendEnabled != rhs.autoLatestTrendEnabled {return false}
    if lhs.latestTrendGeneratedAt != rhs.latestTrendGeneratedAt {return false}
    if lhs.semanticSearchEnabled != rhs.semanticSearchEnabled {return false}
    if lhs.totalEmbeddings != rhs.totalEmbeddings {return false}
    if lhs.pendingEmbeddings != rhs.pendingEmbeddings {return false}
    if lhs.totalEmbeddingDiaries != rhs.totalEmbeddingDiaries {return false}
    if lhs.unknownFields != rhs.unknownFields {return false}
    return true
  }
}
